export const kitchenSinkFormulaColumnSchema = createExcelSchema<{
  customerName: string;
  qty: number;
  unitPrice: number;
  segment: string;
  discountRate: number;
  activatedSeats: number;
}>()
  .column("customerName", {
    header: "Customer",
    accessor: "customerName",
    minWidth: 18,
    headerStyle,
  })
  .column("qty", {
    header: "Qty",
    accessor: "qty",
    width: 8,
    style: {
      alignment: { horizontal: "right" },
    },
    headerStyle,
  })
  .column("unitPrice", {
    header: "Unit Price",
    accessor: "unitPrice",
    minWidth: 12,
    style: currencyStyle,
    headerStyle,
  })
  .column("discountRate", {
    header: "Discount",
    accessor: "discountRate",
    width: 10,
    style: {
      numFmt: "0%",
      alignment: { horizontal: "right" },
    },
    headerStyle,
  })
  .column("activatedSeats", {
    header: "Activated",
    accessor: "activatedSeats",
    width: 10,
    style: {
      alignment: { horizontal: "right" },
    },
    headerStyle,
  })
  .column("grossTotal", {
    header: "Gross",
    formula: ({ row, fx }) => fx.round(row.ref("qty").mul(row.ref("unitPrice")), 2),
    minWidth: 12,
    style: currencyStyle,
    headerStyle,
    summary: (summary) => [summary.formula(({ column, fx }) => fx.round(column.cells().sum(), 2))],
  })
  .column("lineTotal", {
    header: "Net",
    formula: ({ row, fx }) =>
      fx.round(row.ref("grossTotal").mul(row.literal(1).sub(row.ref("discountRate"))), 2),
    minWidth: 12,
    style: currencyStyle,
    conditionalStyle: (c) =>
      c
        .when(({ row }) => row.ref("lineTotal").lt(1000), {
          fill: { color: { rgb: "FEE2E2" } },
          font: { color: { rgb: "991B1B" }, bold: true },
        })
        .when(
          ({ row, fx }) =>
            fx.and(row.ref("lineTotal").gte(5000), row.ref("seatUtilization").gte(0.85)),
          {
            fill: { color: { rgb: "DCFCE7" } },
            font: { color: { rgb: "166534" }, bold: true },
          },
        ),
    headerStyle,
    summary: (summary) => [summary.formula(({ column, fx }) => fx.round(column.cells().sum(), 2))],
  })
  .column("seatUtilization", {
    header: "Utilization",
    formula: ({ row, fx }) =>
      fx.if(row.ref("qty").gt(0), fx.round(row.ref("activatedSeats").div(row.ref("qty")), 4), 0),
    width: 12,
    style: {
      numFmt: "0.0%",
      alignment: { horizontal: "right" },
    },
    headerStyle,
  })
  .column("segment", {
    header: "Segment",
    formula: ({ row, fx }) =>
      fx.if(
        row.ref("lineTotal").gte(5000).or(row.ref("seatUtilization").gte(0.85)),
        "HIGH",
        fx.if(row.ref("discountRate").gte(0.15), "WATCH", "STANDARD"),
      ),
    minWidth: 12,
    headerStyle,
  })
  .column("riskFlag", {
    header: "Risk",
    formula: ({ row, fx }) =>
      fx.if(row.ref("segment").eq("WATCH").or(row.ref("seatUtilization").lt(0.5)), "REVIEW", "OK"),
    minWidth: 10,
    conditionalStyle: (c) =>
      c
        .when(({ row }) => row.ref("riskFlag").eq("REVIEW"), {
          fill: { color: { rgb: "FFEDD5" } },
          font: { color: { rgb: "9A3412" }, bold: true },
          border: { left: { style: "thick", color: { rgb: "EA580C" } } },
        })
        .when(({ row }) => row.ref("riskFlag").eq("OK"), {
          fill: { color: { rgb: "DCFCE7" } },
          font: { color: { rgb: "166534" }, bold: true },
        }),
    headerStyle,
  })
  .build();

export const kitchenSinkGroupedFormulaSchema = createExcelSchema<{
  amount: number;
  customerName: string;
  region: "AMER" | "APAC" | "EMEA";
}>({ mode: "excel-table" })
  .column("customerName", {
    header: "Customer",
    accessor: "customerName",
    minWidth: 18,
    totalsRow: { label: "AVERAGE" },
  })
  .column("amount", {
    header: "Amount",
    accessor: "amount",
    minWidth: 12,
    style: currencyStyle,
    totalsRow: { function: "average" },
  })
  .column("region", {
    header: "Region",
    accessor: "region",
    minWidth: 10,
  })
  .group("regions", (builder, regions: Array<"AMER" | "APAC" | "EMEA">) => {
    for (const region of regions) {
      builder.column(`region:${region}`, {
        header: `${region} Amount`,
        formula: ({ row, fx }) => fx.if(row.ref("region").eq(region), row.ref("amount"), 0),
        minWidth: 14,
        style: currencyStyle,
      });
    }
  })
  .column("regionalTotal", {
    header: "Regional Total",
    formula: ({ row }) => row.group("regions").sum(),
    minWidth: 14,
    style: currencyStyle,
    totalsRow: { function: "sum" },
  })
  .column("regionalAverage", {
    header: "Regional Avg",
    formula: ({ row, fx }) => fx.round(row.group("regions").average(), 2),
    minWidth: 14,
    style: currencyStyle,
    totalsRow: { function: "average" },
  })
  .build();

